import json
import hashlib
import time
from dataclasses import dataclass, field
from typing import Any, Generic, TypeVar

T = TypeVar("T")

@dataclass
class PhaseResult:
    phase_name: str
    items: list
    errors: list = field(default_factory=list)
    metadata: dict = field(default_factory=dict)

@dataclass
class AdaptiveGate:
    high_confidence_threshold: float = 0.85
    low_confidence_threshold: float = 0.50
    _recent_confidences: list = field(default_factory=list)
    _window: int = 50

    def record_confidence(self, conf):
        self._recent_confidences.append(conf)
        if len(self._recent_confidences) > self._window:
            self._recent_confidences = self._recent_confidences[-self._window:]

    @property
    def rolling_mean(self):
        if not self._recent_confidences:
            return 0.5
        return sum(self._recent_confidences) / len(self._recent_confidences)

    def telemetry(self):
        mean = self.rolling_mean
        if mean >= self.high_confidence_threshold:
            batch = 50
        elif mean <= self.low_confidence_threshold:
            batch = 5
        else:
            ratio = (mean - self.low_confidence_threshold) / (self.high_confidence_threshold - self.low_confidence_threshold)
            batch = int(5 + ratio * 45)
        return {
            "rolling_mean_confidence": round(mean, 4),
            "sample_size": len(self._recent_confidences),
            "recommended_batch_size": batch,
            "recommended_max_retries": 3 if mean < self.low_confidence_threshold else 1,
        }

class DeduplicationRing:
    def __init__(self):
        self._hashes = set()
    def __len__(self):
        return len(self._hashes)
    def mark_n(self, n):
        for i in range(n):
            self._hashes.add(hashlib.sha256(str(i).encode()).hexdigest())

def battlefield_report(phase_name, results, dedup_ring, adaptive_gate, wall_clock_s, unresolved_anomalies=None):
    lines = ["", "=" * 78, f"  BATTLEFIELD REPORT - Phase: {phase_name}",
             f"  Wall clock: {wall_clock_s:.2f}s", "=" * 78, "",
             "-- DISPOSITION DISTRIBUTION --"]
    total_items, total_errors = 0, 0
    for disp, pr in sorted(results.items()):
        n, e = len(pr.items), len(pr.errors)
        total_items += n
        total_errors += e
        lines.append(f"  {disp:.<30} {n:>5} items, {e:>3} errors")
    lines.extend(["", f"  TOTAL PROCESSED: {total_items}", f"  TOTAL ERRORS: {total_errors}",
                   f"  DEDUP RING SIZE: {len(dedup_ring)}", "", "-- ADAPTIVE GATE STATE --"])
    for k, v in adaptive_gate.telemetry().items():
        lines.append(f"  {k}: {v}")
    if unresolved_anomalies:
        lines.extend(["", f"-- UNRESOLVED ANOMALIES ({len(unresolved_anomalies)}) --"])
        for a in unresolved_anomalies[:5]:
            lines.append(f"  * [{a.get('record_id', '?')}] {a.get('error', '')[:80]}")
    lines.extend(["", "-- NEXT ACTION REQUIRED --"])
    if total_errors > 0:
        lines.append("  -> RECOMMEND: Inspect error payloads.")
    if unresolved_anomalies:
        lines.append("  -> RECOMMEND: Triage anomalies.")
    if adaptive_gate.rolling_mean < adaptive_gate.low_confidence_threshold:
        lines.append("  -> WARNING: Confidence below threshold.")
    if total_errors == 0 and not unresolved_anomalies:
        lines.append("  -> ALL CLEAR: Proceed to commit/export.")
    lines.extend(["", "=" * 78])
    return "\n".join(lines)

# --- Report 1: Healthy pipeline ---
results1 = {
    "exact_match": PhaseResult("exact", items=[{"id": i} for i in range(50)]),
    "fuzzy_match": PhaseResult("fuzzy", items=[{"id": i} for i in range(15)], errors=[{"id": "E1"}]),
    "anomaly": PhaseResult("anomaly", items=[{"id": i} for i in range(3)])
}
dedup = DeduplicationRing()
dedup.mark_n(68)
gate = AdaptiveGate()
for _ in range(20):
    gate.record_confidence(0.88)

report1 = battlefield_report("HEALTHY_PIPELINE", results1, dedup, gate, 12.5)
print(report1)
has_all_clear = "ALL CLEAR" not in report1  # has 1 error so not all clear
has_inspect = "Inspect error" in report1
print(f"\nReport 1 checks: has_inspect={has_inspect}, no_all_clear={has_all_clear}")
